const body = $json;
const required = ['benefit_type', 'user_context', 'answers'];
for (const key of required) {
  if (body[key] === undefined || body[key] === null) {
    return [{ json: { success: false, error_code: 'INVALID_INPUT', message: `Missing ${key}` } }];
  }
}
if (body.benefit_type !== 'ROI_Calculator') {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'benefit_type must be ROI_Calculator' } }];
}
const revenue = Number(body.user_context.annual_revenue);
const pipelineValue = Number(body.answers.pipeline_value ?? body.answers.question_1 ?? 0);
const effortHours = Number(body.answers.manual_effort_hours ?? body.answers.question_2 ?? 0);
if (!Number.isFinite(revenue)) {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'Missing annual_revenue' } }];
}
if (!Number.isFinite(pipelineValue) || !Number.isFinite(effortHours)) {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'pipeline_value and manual_effort_hours must be numeric' } }];
}
return [{ json: { ...body, calc_inputs: { revenue, pipelineValue, effortHours } } }];

if ($json.success === false) {
  return [{ json: $json }];
}
const { revenue, pipelineValue, effortHours } = $json.calc_inputs;
const rawScore = (revenue * 0.02) + (pipelineValue * 0.01) - (effortHours * 10);
const normalizedScore = Math.max(0, Math.min(100, Math.round(rawScore / 1000)));
return [{
  json: {
    ...$json,
    score: normalizedScore,
    summary_seed: normalizedScore >= 75
      ? 'high'
      : normalizedScore >= 45
        ? 'moderate'
        : 'low'
  }
}];

if ($json.success === false) {
  return [{ json: $json }];
}
const summaryByBand = {
  high: 'Your ROI potential is high. Prioritize automation for immediate measurable gains.',
  moderate: 'Your ROI potential is moderate. Address current bottlenecks to increase impact.',
  low: 'Current ROI potential is low. Start with quick wins and baseline performance tracking.'
};
const recommendations = [
  'Automate repetitive presales and quoting tasks.',
  'Track proposal turnaround and engineer effort weekly.',
  'Reinvest savings into high-conversion pipeline stages.'
];
return [{
  json: {
    success: true,
    benefit_type: 'ROI_Calculator',
    score: $json.score,
    summary: summaryByBand[$json.summary_seed],
    recommendations,
    meta: {
      execution_id: $execution.id,
      version: '1.0.0',
      benefit_version: '2026-Q1',
      inputs: $json.calc_inputs
    }
  }
}];
